external_knowledge:
- A 'graduate' refers to an individual who has completed a degree from a university or college; 
- 'credit champions' is a metaphorical expression for those with exceptionally high credit scores, indicating good financial health; 
- A credit score of more than 700 is considered high and indicates a good credit history.

sql:
SELECT DISTINCT applicant_id
FROM loan_applications
ORDER BY applicant_id ASC;

SELECT loan_id
FROM loan_applications
ORDER BY application_date DESC;

SELECT loan_status
FROM loan_applications
WHERE loan_id = '0';

SELECT loan_amount, loan_status
FROM loan_applications
ORDER BY loan_amount DESC;

SELECT loan_id
FROM loan_applications
ORDER BY application_date DESC;
